                        <span class="step-label d-block small mt-1 text-success fw-semibold">@StepNames[step]</span>
                    </button>
                }
                else
                {
                    <div>
                        <span class="step-circle @(status == "current" ? "bg-primary text-white" : "bg-secondary text-white")">
                            @(step + 1)
                        </span>
                        <span class="step-label d-block small mt-1 @(status == "current" ? "fw-semibold" : "text-muted")">
                            @StepNames[step]
                        </span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

